<?php require '../config.php'; require_admin(); require '_nav.php'; $rows=$pdo->query('SELECT o.*,u.name,u.email FROM orders o JOIN users u ON u.id=o.user_id ORDER BY o.id DESC')->fetchAll(); ?>
<!doctype html><html><head><title>Orders</title><link rel="stylesheet" href="/style.css"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div class="dash"><?php admin_nav(); ?><div class="main"><h1>Orders</h1><table class="table"><tr><th>ID</th><th>Customer</th><th>Plan</th><th>Payment</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r):?><tr><td>#<?=h($r['id'])?></td><td><?=h($r['name'])?><br><small><?=h($r['email'])?></small></td><td><?=h($r['plan'])?></td><td><?=h($r['payment_reference'])?></td><td><span class="badge <?=h($r['status'])?>"><?=h($r['status'])?></span></td><td><?php if($r['status']==='pending'):?><form class="inline" method="post" action="/admin/approve.php"><?=csrf_field()?><input type="hidden" name="id" value="<?=h($r['id'])?>"><button class="btn small" onclick="return confirm('Approve and provision this hosting account?')">Approve</button></form><?php else:?>-<?php endif;?></td></tr><?php endforeach;?></table></div></div></body></html>
